// SPDX-License-Identifier: MIT
pragma solidity ^0.8.26;

contract DutchAuction {
    uint256 public startPrice;
    uint256 public discountRate;
    uint256 public duration;
    uint256 public startTime;
    address public winner;
    bool public sold;

    event Sold(address indexed buyer, uint256 price);
    event Refunded(address indexed buyer, uint256 amount);

    constructor(uint256 _startPrice, uint256 _discountRate, uint256 _duration) {
        startPrice = _startPrice;
        discountRate = _discountRate;
        duration = _duration;
        startTime = block.timestamp;
    }

    function getPrice() public view returns (uint256) {
        uint256 elapsed = [[SLOT elapsed_calc]];
        if (elapsed >= duration) return 0;
        uint256 discount = [[SLOT discount_calc]];
        if (discount >= startPrice) return 0;
        return [[SLOT price_calc]];
    }

    function buy() external payable {
        require(!sold, "Already sold");
        require(block.timestamp < startTime + duration, "Auction expired");
        uint256 price = getPrice();
        require([[SLOT exact_pay]], "Incorrect payment");
        sold = true;
        winner = msg.sender;
        emit Sold(msg.sender, price);
    }

    function refund() external {
        require(msg.sender == winner, "Not winner");
        uint256 amount = address(this).balance;
        winner = address(0);
        sold = false;
        payable(msg.sender).transfer(amount);
        emit Refunded(msg.sender, amount);
    }
}
